#include <stdio.h>

void bubbleSort(int arr[], int n) {
 for (int i = 0; i < n - 1; i++) {
 for (int j = 0; j < n - i - 1; j++) {
 if (arr[j] > arr[j + 1]) {
 int temp = arr[j];
 arr[j] = arr[j + 1];
 arr[j + 1] = temp;
 }
 }
 }
}

// Optimized version
void bubbleSortOptimized(int arr[], int n) {
 for (int i = 0; i < n - 1; i++) {
 int swapped = 0;
 for (int j = 0; j < n - i - 1; j++) {
 if (arr[j] > arr[j + 1]) {
 int temp = arr[j];
 arr[j] = arr[j + 1];
 arr[j + 1] = temp;
 swapped = 1;
 }
 }
 if (!swapped) break; // Already sorted
 }
}

int main() {
 int arr[] = {64, 34, 25, 12, 22, 11, 90};
 int n = 7;
 bubbleSortOptimized(arr, n);
 for (int i = 0; i < n; i++) printf("%d ", arr[i]);
 return 0;
}

def bubble_sort(arr):
 n = len(arr)
 for i in range(n - 1):
 for j in range(n - i - 1):
 if arr[j] > arr[j + 1]:
 arr[j], arr[j + 1] = arr[j + 1], arr[j]
 return arr

def bubble_sort_optimized(arr):
 n = len(arr)
 for i in range(n - 1):
 swapped = False
 for j in range(n - i - 1):
 if arr[j] > arr[j + 1]:
 arr[j], arr[j + 1] = arr[j + 1], arr[j]
 swapped = True
 if not swapped:
 break # Already sorted
 return arr

arr = [64, 34, 25, 12, 22, 11, 90]
print(bubble_sort_optimized(arr.copy()))

class BubbleSort {
 public static void bubbleSort(int[] arr) {
 int n = arr.length;
 for (int i = 0; i < n - 1; i++) {
 boolean swapped = false;
 for (int j = 0; j < n - i - 1; j++) {
 if (arr[j] > arr[j + 1]) {
 int temp = arr[j];
 arr[j] = arr[j + 1];
 arr[j + 1] = temp;
 swapped = true;
 }
 }
 if (!swapped) break;
 }
 }

 public static void main(String[] args) {
 int[] arr = {64, 34, 25, 12, 22, 11, 90};
 bubbleSort(arr);
 for (int x : arr) System.out.print(x + " ");
 }
}
